  ('aboriginal-7be5e2bb-moex-00003', 'aboriginal-7be5e2bb', 'aboriginal-7be5e2bb-moex-114-3082b5f1', 'sub-aboriginal-7be5e2bb-01', NULL, 'single_choice', '下列何者非屬不確定法律概念？', '["食品安全衛生管理法第15條之「有毒或含有害人體健康之物質或異物」", "建築法第58條之「危害公共安全者」", "空氣污染防制法第62條之「通知限期補正或改善」", "廢棄物清理法第2條之「有害事業廢棄物」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "507", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "體育行政"}'::jsonb, NULL),
  ('aboriginal-7be5e2bb-moex-00004', 'aboriginal-7be5e2bb', 'aboriginal-7be5e2bb-moex-114-3082b5f1', 'sub-aboriginal-7be5e2bb-01', NULL, 'single_choice', '關於公立中小學與學生之法律關係，下列敘述何者正確？', '["學校不得對學生作成行政處分", "學生與學校成立公法上之營造物利用關係", "學校制定學生退學之校規，無需任何法律依據", "學生與學校間之營造物利用關係發生爭執時，僅得透過家長會協議解決"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "507", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "體育行政"}'::jsonb, NULL),
  ('aboriginal-7be5e2bb-moex-00005', 'aboriginal-7be5e2bb', 'aboriginal-7be5e2bb-moex-114-3082b5f1', 'sub-aboriginal-7be5e2bb-01', NULL, 'single_choice', '下列何者為行政法人？', '["國立故宮博物院", "中央銀行", "國家中山科學研究院", "公平交易委員會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "507", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "體育行政"}'::jsonb, NULL),
  ('aboriginal-7be5e2bb-moex-00006', 'aboriginal-7be5e2bb', 'aboriginal-7be5e2bb-moex-114-3082b5f1', 'sub-aboriginal-7be5e2bb-01', NULL, 'single_choice', '關於行政機關管轄權限之變更，下列敘述何者正確？', '["行政機關依法規委任所屬下級機關執行事務，不需要公告及刊登政府公報或新聞紙", "除有法律明文規定，否則行政機關不得將其權限之一部委託民間團體辦理", "行政機關得僅依行政程序法第15條第2項規定，將其權限委託不相隸屬之行政機關", "行政機關依法規將其權限之一部分，委託民間團體辦理，該民間團體於委託範圍內，視為行政 機關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "507", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "體育行政"}'::jsonb, NULL),
  ('aboriginal-7be5e2bb-moex-00007', 'aboriginal-7be5e2bb', 'aboriginal-7be5e2bb-moex-114-3082b5f1', 'sub-aboriginal-7be5e2bb-01', NULL, 'single_choice', '甲為行政院所屬薦任八職等之公務員，有關將甲移送懲戒之敘述，下列何者錯誤？', '["甲之非執行職務之違法行為，如嚴重損害政府信譽，亦得移送懲戒", "行政院就甲之失職行為，得不經彈劾程序，逕送懲戒法院審理", "監察院對於甲之失職行為，得主動調查，並於彈劾後移送懲戒法院審理", "如甲之失職行為應受免除職務之懲戒處分，而該行為終了已逾 10 年，行政院即無法再將甲移 送懲戒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "507", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "體育行政"}'::jsonb, NULL),
  ('aboriginal-7be5e2bb-moex-00008', 'aboriginal-7be5e2bb', 'aboriginal-7be5e2bb-moex-114-3082b5f1', 'sub-aboriginal-7be5e2bb-01', NULL, 'single_choice', '公務人員對於服務機關或人事主管機關所為下列人事行政行為，何者不得提起復審？', '["評定試用成績不及格", "機關組成性騷擾處理委員會作成性騷擾成立與否之決定", "申誡之懲處", "核定現職人員部分辦公時間進修 50750、51050"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "507", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "體育行政"}'::jsonb, NULL),
  ('aboriginal-7be5e2bb-moex-00009', 'aboriginal-7be5e2bb', 'aboriginal-7be5e2bb-moex-114-3082b5f1', 'sub-aboriginal-7be5e2bb-01', NULL, 'single_choice', '下列何種身分不適用公務員服務法？', '["受主管機關指派於公營事業擔任董事者", "執行政府委託研究案之國立大學教授", "縣立小學兼任總務主任之教師", "現役軍士官"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "507", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "體育行政"}'::jsonb, NULL),
  ('aboriginal-7be5e2bb-moex-00010', 'aboriginal-7be5e2bb', 'aboriginal-7be5e2bb-moex-114-3082b5f1', 'sub-aboriginal-7be5e2bb-01', NULL, 'single_choice', '下列何者為行政規則與法規命令相異之處？', '["由行政機關訂定", "經下達後生效", "屬一般性、抽象性規定", "生效後拘束訂定機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "507", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "體育行政"}'::jsonb, NULL),
  ('aboriginal-7be5e2bb-moex-00011', 'aboriginal-7be5e2bb', 'aboriginal-7be5e2bb-moex-114-3082b5f1', 'sub-aboriginal-7be5e2bb-01', NULL, 'single_choice', '依司法院大法官解釋意旨，關於行政機關就法規所為之釋示，下列敘述何者錯誤？', '["行政機關就法規所為之釋示，係闡明法規之原意，應自釋示發布之日起有其適用", "釋示如有變更，依舊釋示所為行政處分如已確定，原則上不因釋示之變更而受影響", "釋示如有變更，未確定之行政處分即應適用新釋示之規定", "釋示如有變更，新釋示與舊釋示不一致時，舊釋示並非當然錯誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "507", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "體育行政"}'::jsonb, NULL),
  ('aboriginal-7be5e2bb-moex-00012', 'aboriginal-7be5e2bb', 'aboriginal-7be5e2bb-moex-114-3082b5f1', 'sub-aboriginal-7be5e2bb-01', NULL, 'single_choice', '下列行政處分之附款，何者與該處分之目的欠缺正當合理之關聯？', '["直轄市政府核准餐廳業者得在行人徒步區擺設露天桌椅，但附加不得使用免洗餐具之負擔", "針對都市計畫停車場公共設施用地一定距離內建築物核發建築許可時，附加免除其應附停車空 間之法定義務而改以課予繳納公共停車空間所需費用之義務", "核發外國人居留許可時，對其附加若違法滯留而須遣返出境時，應自負費用之負擔", "經濟部對於受疫情影響發生營運困難產業事業作成薪資補助處分時，附加受補助事業不應有對 員工實施無薪假、減薪或裁員等減損員工權益之行為之負擔"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "507", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "體育行政"}'::jsonb, NULL)
